option.value:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --primary-color: #6c63ff;
  --secondary-color: #ff006e;
  --text-color: #333;
  --light-bg: #f8f9ff;
  --white: #fff;
  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  color: var(--text-color);
  background-color: var(--light-bg);
  line-height: 1.6;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

/* Navigation */
.navbar {
  background: var(--white);
  box-shadow: var(--shadow);
  position: sticky;
  top: 0;
  z-index: 1000;
}

.nav-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 70px;
}

.logo {
  font-size: 24px;
  font-weight: bold;
  color: var(--primary-color);
}

.nav-links {
  display: flex;
  list-style: none;
  gap: 30px;
  align-items: center;
}

.nav-links a {
  text-decoration: none;
  color: var(--text-color);
  transition: color 0.3s;
  font-weight: 500;
}

.nav-links a:hover,
.nav-links a.active {
  color: var(--primary-color);
}

.panier-btn {
  background: var(--primary-color);
  color: var(--white) !important;
  padding: 8px 16px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.3s;
}

.panier-btn:hover {
  background: var(--secondary-color) !important;
}

.inscription-btn {
  background: var(--secondary-color);
  color: var(--white) !important;
  padding: 8px 16px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.3s;
}

.inscription-btn:hover {
  background: var(--primary-color) !important;
}

#panier-count {
  background: var(--secondary-color);
  padding: 2px 6px;
  border-radius: 12px;
  font-size: 12px;
  margin-left: 5px;
}

/* Hero Section */
.hero {
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
  padding: 120px 20px;
  text-align: center;
}

.hero-content h1,
.hero-content h2 {
  font-size: 48px;
  margin-bottom: 20px;
}

.hero-content p {
  font-size: 20px;
  margin-bottom: 30px;
}

.btn-primary {
  background: var(--white);
  color: var(--primary-color);
  border: none;
  padding: 12px 30px;
  border-radius: 5px;
  font-size: 16px;
  font-weight: bold;
  cursor: pointer;
  text-align: center;
  transition: transform 0.3s, box-shadow 0.3s;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.2);
}

/* Catalogue */
.catalogue {
  padding: 80px 20px;
  background: var(--white);
}

.catalogue h2,
.catalogue .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

/* Section Actualites */
.actualites {
  padding: 80px 20px;
  background: var(--white);
}

/* Focus produit pleine largeur */
.focus-produit-section {
  padding: 70px 20px;
  background: linear-gradient(120deg, #ecefff 0%, #f8efff 45%, #eef8ff 100%);
}

.focus-produit-card {
  display: grid;
  grid-template-columns: 1.1fr 1fr;
  gap: 30px;
  background: var(--white);
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid rgba(108, 99, 255, 0.15);
  box-shadow: 0 18px 44px rgba(108, 99, 255, 0.18);
  position: relative;
  transition: transform 0.4s cubic-bezier(0.25, 0.8, 0.25, 1), box-shadow 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
}

.focus-produit-card:hover {
  transform: translateY(-6px) scale(1.005);
  box-shadow: 0 28px 60px rgba(108, 99, 255, 0.28);
}

.focus-produit-card::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: linear-gradient(135deg, rgba(108, 99, 255, 0.08), rgba(255, 0, 110, 0.04));
}

/* Wrapper image + badge flottant */
.focus-produit-image-wrapper {
  position: relative;
  grid-column: 1;
  overflow: hidden;
}

.focus-produit-badge {
  position: absolute;
  top: 18px;
  left: 18px;
  background: linear-gradient(135deg, #ffbe00, #ff7b00);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
  padding: 7px 14px;
  border-radius: 999px;
  box-shadow: 0 4px 14px rgba(255, 123, 0, 0.45);
  letter-spacing: 0.3px;
  animation: badgePulse 2.6s ease-in-out infinite;
  z-index: 10;
}

@keyframes badgePulse {
  0%, 100% { transform: scale(1); box-shadow: 0 4px 14px rgba(255, 123, 0, 0.45); }
  50%       { transform: scale(1.07); box-shadow: 0 6px 20px rgba(255, 123, 0, 0.65); }
}

.focus-produit-image {
  width: 100%;
  height: 100%;
  min-height: 320px;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease;
}

.focus-produit-card:hover .focus-produit-image {
  transform: scale(1.04);
}

.focus-produit-content {
  padding: 28px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  grid-column: 2;
  position: relative;
  z-index: 1;
  background: rgba(255, 255, 255, 0.72);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
}

.focus-produit-titre {
  font-size: 30px;
  line-height: 1.25;
  color: var(--primary-color);
  letter-spacing: 0.2px;
}

.focus-produit-resume {
  font-size: 15px;
  color: #555;
  line-height: 1.7;
}

.focus-produit-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.focus-tag {
  display: inline-block;
  padding: 6px 12px;
  border-radius: 999px;
  background: linear-gradient(135deg, #f2f4ff, #eef9ff);
  color: var(--primary-color);
  font-size: 12px;
  font-weight: 600;
  border: 1px solid rgba(108, 99, 255, 0.18);
}

.focus-produit-link {
  margin-top: 6px;
  width: fit-content;
  background: linear-gradient(135deg, var(--primary-color), #867dff);
  color: var(--white);
  text-decoration: none;
  font-weight: 700;
  padding: 11px 18px;
  border-radius: 6px;
  box-shadow: 0 8px 18px rgba(108, 99, 255, 0.35);
  transition: transform 0.3s, box-shadow 0.3s;
}

.focus-produit-link:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 24px rgba(108, 99, 255, 0.45);
}

/* Actualites */
.actualites .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.actualites-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
}

.actualite-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  cursor: pointer;
}

.actualite-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
}

.actualite-image {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
}

.actualite-content {
  padding: 20px;
}

.actualite-date {
  display: inline-block;
  font-size: 12px;
  color: #777;
  margin-bottom: 10px;
}

.actualite-titre {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-color);
  margin-bottom: 10px;
  line-height: 1.35;
}

.actualite-resume {
  font-size: 14px;
  color: #666;
  margin-bottom: 14px;
  line-height: 1.5;
}

.actualite-link {
  display: inline-block;
  color: var(--primary-color);
  font-weight: 600;
  text-decoration: none;
}

.actualite-link:hover {
  color: var(--secondary-color);
  text-decoration: underline;
}

.filtres {
  display: flex;
  justify-content: center;
  gap: 15px;
  margin-bottom: 40px;
  flex-wrap: wrap;
}

.filtre-btn {
  padding: 10px 20px;
  border: 2px solid var(--primary-color);
  background: var(--white);
  color: var(--primary-color);
  border-radius: 25px;
  cursor: pointer;
  transition: all 0.3s;
  font-weight: 500;
}

.filtre-btn.active {
  background: var(--primary-color);
  color: var(--white);
}

.filtre-btn:hover {
  background: var(--primary-color);
  color: var(--white);
}

.livres-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
}

.livre-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  cursor: pointer;
}

.livre-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
}

.livre-couverture {
  width: 100%;
  height: 280px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  padding: 30px 20px;
  position: relative;
  overflow: hidden;
}

.livre-couverture::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 20% 50%, rgba(255, 255, 255, 0.1), transparent),
  radial-gradient(circle at 80% 80%, rgba(0, 0, 0, 0.1), transparent);
  pointer-events: none;
}

.livre-emoji {
  font-size: 80px;
  z-index: 1;
  animation: float 3s ease-in-out infinite;
}

@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}

.livre-couverture-content {
  text-align: center;
  z-index: 1;
  width: 100%;
}

.livre-couverture-titre {
  color: var(--white);
  font-weight: 700;
  font-size: 18px;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
  margin-bottom: 8px;
  line-height: 1.3;
  word-wrap: break-word;
}

.livre-couverture-auteur {
  color: rgba(255, 255, 255, 0.9);
  font-size: 13px;
  text-shadow: 1px 1px 3px rgba(0, 0, 0, 0.2);
  font-style: italic;
}

.livre-card:nth-child(2n) .livre-image {
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
}

.livre-card:nth-child(3n) .livre-image {
  background: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
}

.livre-card:nth-child(4n) .livre-image {
  background: linear-gradient(135deg, #43e97b 0%, #38f9d7 100%);
}

.livre-content {
  padding: 20px;
}

.livre-titre {
  font-size: 18px;
  font-weight: bold;
  margin-bottom: 10px;
  color: var(--text-color);
}

.livre-auteur {
  color: #666;
  font-size: 14px;
  margin-bottom: 10px;
}

.livre-categorie {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 12px;
  margin-bottom: 15px;
}

.livre-prix {
  font-size: 24px;
  font-weight: bold;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.livre-description {
  font-size: 13px;
  color: #666;
  margin-bottom: 15px;
  line-height: 1.5;
}

.livre-duree {
  font-size: 12px;
  color: #999;
  margin-bottom: 15px;
}

.livre-extrait {
  margin-bottom: 15px;
  padding: 12px;
  background: #f0f0f0;
  border-radius: 8px;
  border-left: 4px solid var(--primary-color);
}

.extrait-label {
  display: block;
  font-size: 12px;
  font-weight: 600;
  color: var(--primary-color);
  margin-bottom: 8px;
}

.extrait-audio {
  width: 100%;
  height: 30px;
  border-radius: 4px;
}

.extrait-audio::-webkit-media-controls-panel {
  background-color: #fff;
  border-radius: 4px;
}

.extrait-audio::-webkit-media-controls-play-button,
.extrait-audio::-webkit-media-controls-mute-button,
.extrait-audio::-webkit-media-controls-volume-slider {
  filter: invert(0.8);
}

.btn-ajouter {
  width: 100%;
  padding: 10px;
  background: var(--primary-color);
  color: var(--white);
  border: none;
  border-radius: 5px;
  cursor: pointer;
  font-weight: bold;
  transition: background 0.3s;
}

.btn-ajouter:hover {
  background: var(--secondary-color);
}

.btn-ajouter.ajoute {
  background: #28a745;
}

/* Modal Panier */
.modal {
  display: none;
  position: fixed;
  z-index: 2000;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.5);
}

.modal.active {
  display: flex;
  align-items: center;
  justify-content: center;
}

.modal-content {
  background-color: var(--white);
  padding: 30px;
  border-radius: 10px;
  max-width: 500px;
  width: 90%;
  max-height: 80vh;
  overflow-y: auto;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
}

.close {
  float: right;
  font-size: 28px;
  font-weight: bold;
  cursor: pointer;
  color: var(--text-color);
}

.close:hover {
  color: var(--secondary-color);
}

.modal-content h2,
.modal-content .titre_moyen {
  margin-bottom: 20px;
  color: var(--primary-color);
}

.panier-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 15px 0;
  border-bottom: 1px solid var(--light-bg);
}

.panier-item-info {
  flex-grow: 1;
}

.panier-item-titre {
  font-weight: bold;
  margin-bottom: 5px;
}

.panier-item-prix {
  color: var(--primary-color);
  font-weight: bold;
}

.panier-item-remove {
  background: var(--secondary-color);
  color: var(--white);
  border: none;
  padding: 5px 10px;
  border-radius: 3px;
  cursor: pointer;
  margin-left: 10px;
}

.panier-total {
  margin: 20px 0;
  font-size: 20px;
  text-align: right;
  padding: 15px;
  background: var(--light-bg);
  border-radius: 5px;
}

.panier-vide {
  text-align: center;
  padding: 30px;
  color: #666;
}

/* Contact */
.contact {
  padding: 80px 20px;
  background: var(--light-bg);
}

.contact h2,
.contact .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.contact-form {
  max-width: 600px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.contact-form input,
.contact-form textarea {
  padding: 15px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s;
}

.contact-form input:focus,
.contact-form textarea:focus {
  outline: none;
  border-color: var(--primary-color);
}

.message-success {
  background: #28a745;
  color: var(--white);
  padding: 15px;
  border-radius: 5px;
  text-align: center;
  margin-top: 20px;
}

/* Inscription */
.inscription-form {
  max-width: 500px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 15px;
}

.inscription-form input {
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s;
}

.inscription-form input:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.inscription-form button {
  margin-top: 10px;
}

.inscription-modal {
  max-width: 550px;
}

/* Page Compte */
.compte-section {
  padding: 60px 20px;
  background: linear-gradient(135deg, #f8f9ff 0%, #f3f0ff 100%);
  min-height: calc(100vh - 200px);
}

.compte-container {
  max-width: 600px;
  margin: 0 auto;
  background: var(--white);
  padding: 40px;
  border-radius: 10px;
  box-shadow: var(--shadow);
}

.compte-container h1 {
  font-size: 32px;
  color: var(--primary-color);
  margin-bottom: 10px;
  text-align: center;
}

.compte-description {
  text-align: center;
  color: #666;
  margin-bottom: 30px;
  font-size: 16px;
}

.inscription-form-page {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-group label {
  font-weight: 600;
  color: var(--text-color);
  font-size: 14px;
}

.form-group input {
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s, box-shadow 0.3s;
}

.form-group input:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.form-group small {
  font-size: 12px;
  color: #999;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.form-group.checkbox {
  flex-direction: row;
  align-items: flex-start;
  gap: 10px;
}

.form-group.checkbox input {
  width: 20px;
  height: 20px;
  cursor: pointer;
  margin-top: 2px;
}

.checkbox-label {
  font-size: 14px;
  color: #666;
  cursor: pointer;
  font-weight: 400;
  margin: 0;
}

.btn-large {
  padding: 14px 30px;
  font-size: 16px;
  margin-top: 10px;
}

.message-large {
  text-align: center;
  padding: 40px 20px;
}

.message-large p {
  margin: 8px 0;
}

.compte-lien {
  text-align: center;
  margin-top: 30px;
  padding-top: 30px;
  border-top: 1px solid #eee;
}

.compte-lien p {
  color: #666;
}

.compte-lien a {
  color: var(--primary-color);
  text-decoration: none;
  font-weight: 600;
  transition: color 0.3s;
}

.compte-lien a:hover {
  color: var(--secondary-color);
}

/* Page Abonnement */
.abonnement-section {
  padding: 60px 20px;
  background: var(--white);
}

.abonnement-header {
  text-align: center;
  margin-bottom: 50px;
}

.abonnement-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.abonnement-description {
  font-size: 18px;
  color: #666;
  max-width: 500px;
  margin: 0 auto;
}

.tableau-container {
  margin-bottom: 60px;
  overflow-x: auto;
}

.tableau-abonnements {
  width: 100%;
  border-collapse: collapse;
  background: var(--white);
  box-shadow: var(--shadow);
  border-radius: 10px;
  overflow: hidden;
}

.tableau-abonnements thead {
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
}

.tableau-abonnements th {
  padding: 20px;
  text-align: left;
  font-weight: 600;
  font-size: 14px;
}

.tableau-abonnements td {
  padding: 20px;
  border-bottom: 1px solid #f0f0f0;
  font-size: 14px;
}

.tableau-abonnements tbody tr:last-child td {
  border-bottom: none;
}

.formule-row {
  transition: background-color 0.3s;
}

.formule-row:hover {
  background-color: #f9f8ff;
}

.formule-nom {
  position: relative;
}

.nom-formule {
  font-weight: 700;
  font-size: 16px;
  color: var(--primary-color);
}

.badge-populaire {
  display: inline-block;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: var(--white);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  margin-top: 5px;
}

.badge-premium {
  display: inline-block;
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  color: var(--white);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  margin-top: 5px;
}

.promo-badge {
  display: inline-block;
  background: #ff6b6b;
  color: var(--white);
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 12px;
  font-weight: 600;
  margin-left: 10px;
}

.prix-principal {
  font-size: 18px;
  font-weight: 700;
  color: var(--primary-color);
}

.badge-oui {
  display: inline-block;
  background: #d4edda;
  color: #155724;
  padding: 4px 8px;
  border-radius: 4px;
  font-weight: 600;
  font-size: 12px;
}

.badge-non {
  display: inline-block;
  background: #f8d7da;
  color: #721c24;
  padding: 4px 8px;
  border-radius: 4px;
  font-weight: 600;
  font-size: 12px;
}

.badge {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 12px;
}

.btn-secondary {
  background: #6c757d;
  color: var(--white);
}

.btn-secondary:hover {
  background: #5a6268;
}

.btn-special {
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  color: var(--white);
}

.btn-special:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(245, 87, 108, 0.4);
}

.btn-small {
  padding: 8px 16px;
  font-size: 13px;
}

.tableau-note {
  text-align: right;
  font-size: 12px;
  color: #999;
  margin-top: 15px;
}

.abonnement-section-titre {
  text-align: center;
  margin: 60px 0 40px;
}

.abonnement-section-titre h2,
.abonnement-section-titre .titre_moyen {
  font-size: 32px;
  color: var(--primary-color);
}

.avantages-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-bottom: 60px;
}

.avantage-card {
  background: var(--light-bg);
  padding: 30px;
  border-radius: 10px;
  text-align: center;
  transition: transform 0.3s, box-shadow 0.3s;
}

.avantage-card:hover {
  transform: translateY(-10px);
  box-shadow: var(--shadow);
}

.avantage-icon {
  font-size: 40px;
  margin-bottom: 15px;
}

.avantage-card h3 {
  font-size: 18px;
  color: var(--primary-color);
  margin-bottom: 10px;
}

.avantage-card p {
  color: #666;
  font-size: 14px;
}

/* FAQ */
.faq-container {
  max-width: 800px;
  margin: 0 auto;
}

.faq-item {
  background: var(--light-bg);
  border-radius: 8px;
  margin-bottom: 15px;
  overflow: hidden;
}

.faq-question {
  padding: 20px;
  cursor: pointer;
  display: flex;
  justify-content: space-between;
  align-items: center;
  user-select: none;
  transition: background 0.3s;
}

.faq-question:hover {
  background: #f0ecff;
}

.faq-toggle {
  font-size: 24px;
  color: var(--primary-color);
  font-weight: 300;
}

.faq-answer {
  padding: 0 20px 20px;
  color: #666;
  line-height: 1.6;
}

.faq-answer p {
  margin: 0;
}

/* Page Nouveautés */
.nouveaute-section {
  padding: 60px 20px;
  background: var(--white);
  min-height: 100vh;
}

.nouveaute-header {
  text-align: center;
  margin-bottom: 50px;
}

.nouveaute-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.nouveaute-description {
  font-size: 18px;
  color: #666;
  max-width: 500px;
  margin: 0 auto;
}

/* Onglets */
.onglets-container {
  margin-bottom: 40px;
}

.onglets-list {
  display: flex;
  gap: 15px;
  justify-content: center;
  flex-wrap: wrap;
  border-bottom: 2px solid #f0f0f0;
  padding-bottom: 0;
}

.onglet-btn {
  padding: 15px 25px;
  border: none;
  background: transparent;
  color: #666;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s;
  position: relative;
  display: flex;
  align-items: center;
  gap: 8px;
}

.onglet-icon {
  font-size: 18px;
}

.onglet-btn:hover {
  color: var(--primary-color);
}

.onglet-btn.active {
  color: var(--primary-color);
}

.onglet-btn.active::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));
  border-radius: 2px 2px 0 0;
}

/* Grille des Nouvelles */
.nouveaute-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 25px;
  margin-bottom: 50px;
}

.nouvelle-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  display: flex;
  flex-direction: column;
}

.nouvelle-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.15);
}

.nouvelle-couverture {
  width: 100%;
  height: 200px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.nouvelle-couverture::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 20% 50%, rgba(255, 255, 255, 0.1), transparent),
  radial-gradient(circle at 80% 80%, rgba(0, 0, 0, 0.1), transparent);
  pointer-events: none;
}

.nouvelle-emoji {
  font-size: 60px;
  z-index: 1;
  animation: float 3s ease-in-out infinite;
}

.nouvelle-nouveau {
  position: absolute;
  top: 10px;
  right: 10px;
  background: #ff6b6b;
  color: var(--white);
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1px;
  box-shadow: 0 4px 10px rgba(255, 107, 107, 0.3);
  z-index: 2;
}

.nouvelle-content {
  padding: 20px;
  flex-grow: 1;
  display: flex;
  flex-direction: column;
}

.nouvelle-date {
  font-size: 11px;
  color: #999;
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.nouvelle-titre {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-color);
  margin-bottom: 8px;
  line-height: 1.3;
}

.nouvelle-auteur {
  font-size: 13px;
  color: #666;
  margin-bottom: 10px;
}

.nouvelle-categorie {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 11px;
  margin-bottom: 10px;
  width: fit-content;
}

.nouvelle-description {
  font-size: 13px;
  color: #666;
  margin-bottom: 10px;
  line-height: 1.5;
  flex-grow: 1;
}

.nouvelle-duree {
  font-size: 12px;
  color: #999;
  margin-bottom: 10px;
}

.nouvelle-prix {
  font-size: 20px;
  font-weight: 700;
  color: var(--primary-color);
  margin-bottom: 12px;
}

/* Pagination */
.pagination-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 30px;
  padding: 40px 20px;
  background: var(--light-bg);
  border-radius: 10px;
}

.pagination-info {
  font-size: 15px;
  color: #666;
  font-weight: 500;
}

.pagination-controls {
  display: flex;
  align-items: center;
  gap: 15px;
  flex-wrap: wrap;
  justify-content: center;
}

.pagination-btn {
  padding: 10px 18px;
  border: 2px solid var(--primary-color);
  background: var(--white);
  color: var(--primary-color);
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s;
}

.pagination-btn:hover:not(:disabled) {
  background: var(--primary-color);
  color: var(--white);
}

.pagination-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pagination-numbers {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.pagination-number {
  width: 36px;
  height: 36px;
  border: 2px solid #ddd;
  background: var(--white);
  color: var(--text-color);
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pagination-number:hover:not(.active) {
  border-color: var(--primary-color);
  color: var(--primary-color);
}

.pagination-number.active {
  background: var(--primary-color);
  color: var(--white);
  border-color: var(--primary-color);
}

.pagination-ellipsis {
  padding: 0 6px;
  color: #999;
}

/* Page Sondage */
.sondage-section {
  padding: 60px 20px;
  background: var(--white);
  min-height: 100vh;
}

.sondage-header {
  text-align: center;
  margin-bottom: 60px;
}

.sondage-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.sondage-description {
  font-size: 18px;
  color: #666;
  max-width: 600px;
  margin: 0 auto;
}

.sondage-form-container {
  max-width: 700px;
  margin: 0 auto;
}

.sondage-form {
  background: var(--light-bg);
  padding: 40px;
  border-radius: 10px;
  box-shadow: var(--shadow);
}

.sondage-progress {
  margin-bottom: 40px;
}

.progress-bar {
  width: 100%;
  height: 8px;
  background: #e0e0e0;
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 10px;
}

.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));
  transition: width 0.3s ease;
  width: 0%;
}

.progress-text {
  font-size: 13px;
  color: #666;
  text-align: center;
}

.sondage-question {
  margin-bottom: 35px;
  padding-bottom: 35px;
  border-bottom: 1px solid #e0e0e0;
}

.sondage-question:last-of-type {
  border-bottom: none;
}

.question-label {
  display: block;
  font-size: 16px;
  color: var(--text-color);
  margin-bottom: 20px;
  line-height: 1.5;
}

.question-response {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.question-response.stars {
  flex-direction: row;
  gap: 5px;
  justify-content: center;
  flex-wrap: wrap;
}

.question-response.stars input {
  display: none;
}

.star-label {
  font-size: 24px;
  cursor: pointer;
  transition: transform 0.2s, filter 0.2s;
  user-select: none;
  filter: grayscale(100%);
}

.question-response.stars input:checked ~ .star-label,
.star-label:hover,
.question-response.stars input:checked + .star-label ~ .star-label:hover {
  filter: grayscale(0%);
}

.question-response.stars input:checked + .star-label {
  transform: scale(1.2);
}

.radio-label,
.checkbox-label {
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  padding: 12px;
  border-radius: 6px;
  transition: all 0.3s;
  user-select: none;
}

.radio-label:hover,
.checkbox-label:hover {
  background: rgba(108, 99, 255, 0.05);
}

.radio-label input[type="radio"],
.checkbox-label input[type="checkbox"] {
  cursor: pointer;
  width: 18px;
  height: 18px;
  accent-color: var(--primary-color);
}

.radio-label span,
.checkbox-label span {
  font-size: 14px;
  color: var(--text-color);
  flex: 1;
}

.question-response textarea {
  width: 100%;
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 6px;
  font-family: inherit;
  font-size: 14px;
  resize: vertical;
  transition: border-color 0.3s;
}

.question-response textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.question-response small {
  font-size: 12px;
  color: #999;
  margin-top: 5px;
}

.sondage-actions {
  margin-top: 40px;
  text-align: center;
}

.confidentialite {
  font-size: 12px;
  color: #999;
  margin-top: 15px;
}

.sondage-confirmation {
  max-width: 600px;
  margin: 60px auto;
  background: var(--light-bg);
  padding: 60px 40px;
  border-radius: 10px;
  text-align: center;
}

.confirmation-content {
  animation: slideIn 0.5s ease;
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.confirmation-icon {
  font-size: 60px;
  margin-bottom: 20px;
}

.sondage-confirmation h2,
.sondage-confirmation .titre_moyen {
  font-size: 28px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.sondage-confirmation p {
  font-size: 15px;
  color: #666;
  margin: 10px 0;
  line-height: 1.6;
}

.confirmation-message {
  font-weight: 500;
  color: var(--primary-color);
  margin: 20px 0;
}

.sondage-confirmation .btn-primary {
  margin-top: 30px;
}

/* Responsive - Sondage */
@media (max-width: 768px) {
  .sondage-form {
    padding: 30px 20px;
  }

  .sondage-header h1 {
    font-size: 28px;
  }

  .sondage-question {
    margin-bottom: 25px;
    padding-bottom: 25px;
  }
}

@media (max-width: 480px) {
  .sondage-section {
    padding: 30px 15px;
  }

  .sondage-form {
    padding: 20px;
  }

  .sondage-header h1 {
    font-size: 24px;
  }

  .sondage-description {
    font-size: 14px;
  }

  .question-label {
    font-size: 14px;
  }

  .question-response.stars {
    gap: 2px;
  }

  .star-label {
    font-size: 20px;
  }

  .radio-label,
  .checkbox-label {
    padding: 10px;
    font-size: 13px;
  }

  .sondage-confirmation {
    padding: 40px 20px;
  }

  .confirmation-icon {
    font-size: 48px;
  }

  .sondage-confirmation h2,
  .sondage-confirmation .titre_moyen {
    font-size: 22px;
  }
}

/* Responsive - Nouvelles */
@media (max-width: 768px) {
  .onglets-list {
    gap: 10px;
  }

  .onglet-btn {
    padding: 12px 15px;
    font-size: 13px;
  }

  .onglet-icon {
    display: none;
  }

  .nouveaute-grid {
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 15px;
  }

  .pagination-controls {
    flex-direction: column;
  }

  .pagination-numbers {
    justify-content: center;
  }
}

@media (max-width: 480px) {
  .onglet-btn {
    padding: 10px 12px;
    font-size: 12px;
  }

  .onglet-btn.active::after {
    height: 2px;
  }

  .nouveaute-grid {
    grid-template-columns: 1fr;
    gap: 15px;
  }

  .pagination-number {
    width: 32px;
    height: 32px;
    font-size: 13px;
  }

  .nouvelle-couverture {
    height: 180px;
  }

  .nouvelle-emoji {
    font-size: 50px;
  }
}

/* Carousel Section */
.carousel-section {
  padding: 80px 20px;
  background: var(--white);
}

.carousel-section h2,
.carousel-section .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.carousel-container {
  display: flex;
  align-items: center;
  gap: 20px;
  position: relative;
}

.carousel-wrapper {
  flex: 1;
  overflow: hidden;
  border-radius: 10px;
  box-shadow: var(--shadow);
  background: var(--light-bg);
}

.carousel {
  display: flex;
  transition: transform 0.5s ease-in-out;
}

.carousel-slide {
  min-width: 100%;
  display: flex;
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
  padding: 40px;
  align-items: center;
  gap: 40px;
  animation: slideIn 0.5s ease-in-out;
}

@keyframes slideIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.carousel-slide-image {
  flex-shrink: 0;
  font-size: 120px;
  animation: float 3s ease-in-out infinite;
}

.carousel-slide-content {
  flex: 1;
}

.carousel-slide-title {
  font-size: 32px;
  font-weight: bold;
  margin-bottom: 15px;
}

.carousel-slide-author {
  font-size: 18px;
  opacity: 0.9;
  margin-bottom: 15px;
}

.carousel-slide-description {
  font-size: 16px;
  opacity: 0.9;
  margin-bottom: 20px;
  line-height: 1.5;
}

.carousel-slide-details {
  display: flex;
  gap: 30px;
  margin-bottom: 25px;
  flex-wrap: wrap;
}

.carousel-slide-detail {
  display: flex;
  flex-direction: column;
}

.carousel-slide-detail-label {
  font-size: 12px;
  opacity: 0.8;
  text-transform: uppercase;
  margin-bottom: 5px;
  letter-spacing: 1px;
}

.carousel-slide-detail-value {
  font-size: 20px;
  font-weight: bold;
}

.carousel-slide-price {
  font-size: 36px;
  font-weight: bold;
  margin-bottom: 25px;
}

.carousel-btn-add {
  background: var(--white);
  color: var(--primary-color);
  border: none;
  padding: 12px 30px;
  border-radius: 5px;
  font-size: 16px;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.3s;
}

.carousel-btn-add:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);
}

.carousel-btn-add.ajoute {
  background: #28a745;
  color: var(--white);
}

.carousel-btn {
  background: var(--primary-color);
  color: var(--white);
  border: none;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  cursor: pointer;
  font-size: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s;
  flex-shrink: 0;
}

.carousel-btn:hover {
  background: var(--secondary-color);
  transform: scale(1.1);
}

.carousel-btn.prev {
  order: -1;
}

.carousel-dots {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin-top: 25px;
  flex-wrap: wrap;
}

.carousel-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: #ddd;
  cursor: pointer;
  transition: all 0.3s;
  border: 2px solid transparent;
}

.carousel-dot.active {
  background: var(--primary-color);
  width: 30px;
  border-radius: 6px;
}

.carousel-dot:hover {
  background: var(--secondary-color);
}

@media (max-width: 768px) {
  .carousel-slide {
    flex-direction: column;
    padding: 30px 20px;
    gap: 20px;
  }

  .carousel-slide-image {
    font-size: 80px;
  }

  .carousel-slide-title {
    font-size: 24px;
  }

  .carousel-slide-details {
    gap: 15px;
  }

  .carousel-slide-price {
    font-size: 28px;
  }

  .carousel-btn {
    width: 40px;
    height: 40px;
    font-size: 18px;
  }
}

@media (max-width: 480px) {
  .carousel-container {
    gap: 10px;
  }

  .carousel-slide {
    padding: 20px 15px;
  }

  .carousel-slide-image {
    font-size: 60px;
  }

  .carousel-slide-title {
    font-size: 20px;
  }

  .carousel-slide-author {
    font-size: 14px;
  }

  .carousel-slide-description {
    font-size: 14px;
  }

  .carousel-btn {
    width: 35px;
    height: 35px;
    font-size: 16px;
  }

  .carousel-btn-add {
    padding: 10px 20px;
    font-size: 14px;
  }
}

/* Footer */
.footer {
  background: var(--text-color);
  color: var(--white);
  padding: 40px 20px;
  text-align: center;
}

.footer p {
  margin: 10px 0;
}

.footer-extra {
  margin-top: 24px;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.2);
}

.footer-columns {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 20px;
  text-align: left;
}

.footer-section h3 {
  font-size: 16px;
  margin-bottom: 10px;
  color: #fff;
}

.footer-list {
  list-style: none;
  padding: 0;
  margin: 0;
}

.footer-list li {
  margin-bottom: 6px;
}

.footer-list a,
.footer-accessibility {
  color: rgba(255, 255, 255, 0.9);
  text-decoration: none;
  font-size: 14px;
}

.footer-list a:hover {
  color: #fff;
  text-decoration: underline;
}

/* Responsive */
@media (max-width: 768px) {
  .nav-links {
    gap: 15px;
  }

  .hero-content h1,
  .hero-content h2 {
    font-size: 32px;
  }

  .livres-grid {
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 20px;
  }

  .focus-produit-card {
    grid-template-columns: 1fr 1fr;
    gap: 20px;
  }

  .focus-produit-image {
    min-height: 240px;
  }

  .focus-produit-titre {
    font-size: 26px;
  }

  .actualites-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .catalogue h2,
  .contact h2,
  .catalogue .titre_moyen,
  .contact .titre_moyen {
    font-size: 28px;
  }

  .form-row {
    grid-template-columns: 1fr;
  }

  .compte-container {
    padding: 30px 20px;
  }

  .livre-couverture {
    height: 240px;
  }

  .livre-emoji {
    font-size: 60px;
  }

  .livre-couverture-titre {
    font-size: 16px;
  }

  .footer-columns {
    grid-template-columns: 1fr;
    text-align: center;
  }
}

@media (max-width: 480px) {
  .nav-links {
    gap: 10px;
    flex-wrap: wrap;
  }

  .hero-content h1,
  .hero-content h2 {
    font-size: 24px;
  }

  .livres-grid {
    grid-template-columns: 1fr;
  }

  .focus-produit-section {
    padding: 50px 15px;
  }

  .focus-produit-content {
    padding: 20px;
  }

  .focus-produit-titre {
    font-size: 22px;
  }

  .focus-produit-resume {
    font-size: 14px;
  }

  .focus-produit-link {
    width: 100%;
    text-align: center;
  }

  .actualites-grid {
    grid-template-columns: 1fr;
  }

  .modal-content {
    padding: 20px;
  }

  .compte-section {
    padding: 30px 15px;
  }

  .compte-container {
    padding: 20px;
  }

  .compte-container h1 {
    font-size: 24px;
  }

  .livre-couverture {
    height: 200px;
  }

  .livre-emoji {
    font-size: 50px;
  }

  .livre-couverture-titre {
    font-size: 14px;
  }

  .livre-couverture-auteur {
    font-size: 11px;
  }
}

.social {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  padding: 20px;
  background-color: #333;
  color: #fff;
}

.social .titre_moyen {
  font-size: 20px;
  font-weight: 700;
}

.social-links {
  display: flex;
  gap: 1.5rem;
  margin-top: 1rem;
  justify-content: center;
}

.social-links a {
  width: 2rem;
  height: 2rem;
  color: #fff;
  transition: color 0.3s ease;
}

.social-links a:hover {
  color: #667eea;
}

.social-links svg {
  width: 100%;
  height: 100%;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --primary-color: #6c63ff;
  --secondary-color: #ff006e;
  --text-color: #333;
  --light-bg: #f8f9ff;
  --white: #fff;
  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  color: var(--text-color);
  background-color: var(--light-bg);
  line-height: 1.6;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

/* Navigation */
.navbar {
  background: var(--white);
  box-shadow: var(--shadow);
  position: sticky;
  top: 0;
  z-index: 1000;
}

.nav-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 70px;
}

.logo {
  font-size: 24px;
  font-weight: bold;
  color: var(--primary-color);
}

.nav-links {
  display: flex;
  list-style: none;
  gap: 30px;
  align-items: center;
}

.nav-links a {
  text-decoration: none;
  color: var(--text-color);
  transition: color 0.3s;
  font-weight: 500;
}

.nav-links a:hover,
.nav-links a.active {
  color: var(--primary-color);
}

.panier-btn {
  background: var(--primary-color);
  color: var(--white) !important;
  padding: 8px 16px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.3s;
}

.panier-btn:hover {
  background: var(--secondary-color) !important;
}

.inscription-btn {
  background: var(--secondary-color);
  color: var(--white) !important;
  padding: 8px 16px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.3s;
}

.inscription-btn:hover {
  background: var(--primary-color) !important;
}

#panier-count {
  background: var(--secondary-color);
  padding: 2px 6px;
  border-radius: 12px;
  font-size: 12px;
  margin-left: 5px;
}

/* Hero Section */
.hero {
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
  padding: 120px 20px;
  text-align: center;
}

.hero-content h1,
.hero-content h2 {
  font-size: 48px;
  margin-bottom: 20px;
}

.hero-content p {
  font-size: 20px;
  margin-bottom: 30px;
}

.btn-primary {
  background: var(--white);
  color: var(--primary-color);
  border: none;
  padding: 12px 30px;
  border-radius: 5px;
  font-size: 16px;
  font-weight: bold;
  cursor: pointer;
  text-align: center;
  transition: transform 0.3s, box-shadow 0.3s;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.2);
}

/* Catalogue */
.catalogue {
  padding: 80px 20px;
  background: var(--white);
}

.catalogue h2,
.catalogue .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

/* Section Actualites */
.actualites {
  padding: 80px 20px;
  background: var(--white);
}

/* Focus produit pleine largeur */
.focus-produit-section {
  padding: 70px 20px;
  background: linear-gradient(120deg, #ecefff 0%, #f8efff 45%, #eef8ff 100%);
}

.focus-produit-card {
  display: grid;
  grid-template-columns: 1.1fr 1fr;
  gap: 30px;
  background: var(--white);
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid rgba(108, 99, 255, 0.15);
  box-shadow: 0 18px 44px rgba(108, 99, 255, 0.18);
  position: relative;
  transition: transform 0.4s cubic-bezier(0.25, 0.8, 0.25, 1), box-shadow 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
}

.focus-produit-card:hover {
  transform: translateY(-6px) scale(1.005);
  box-shadow: 0 28px 60px rgba(108, 99, 255, 0.28);
}

.focus-produit-card::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: linear-gradient(135deg, rgba(108, 99, 255, 0.08), rgba(255, 0, 110, 0.04));
}

/* Wrapper image + badge flottant */
.focus-produit-image-wrapper {
  position: relative;
  grid-column: 1;
  overflow: hidden;
}

.focus-produit-badge {
  position: absolute;
  top: 18px;
  left: 18px;
  background: linear-gradient(135deg, #ffbe00, #ff7b00);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
  padding: 7px 14px;
  border-radius: 999px;
  box-shadow: 0 4px 14px rgba(255, 123, 0, 0.45);
  letter-spacing: 0.3px;
  animation: badgePulse 2.6s ease-in-out infinite;
  z-index: 10;
}

@keyframes badgePulse {
  0%, 100% { transform: scale(1); box-shadow: 0 4px 14px rgba(255, 123, 0, 0.45); }
  50%       { transform: scale(1.07); box-shadow: 0 6px 20px rgba(255, 123, 0, 0.65); }
}

.focus-produit-image {
  width: 100%;
  height: 100%;
  min-height: 320px;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease;
}

.focus-produit-card:hover .focus-produit-image {
  transform: scale(1.04);
}

.focus-produit-content {
  padding: 28px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  grid-column: 2;
  position: relative;
  z-index: 1;
  background: rgba(255, 255, 255, 0.72);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
}

.focus-produit-titre {
  font-size: 30px;
  line-height: 1.25;
  color: var(--primary-color);
  letter-spacing: 0.2px;
}

.focus-produit-resume {
  font-size: 15px;
  color: #555;
  line-height: 1.7;
}

.focus-produit-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.focus-tag {
  display: inline-block;
  padding: 6px 12px;
  border-radius: 999px;
  background: linear-gradient(135deg, #f2f4ff, #eef9ff);
  color: var(--primary-color);
  font-size: 12px;
  font-weight: 600;
  border: 1px solid rgba(108, 99, 255, 0.18);
}

.focus-produit-link {
  margin-top: 6px;
  width: fit-content;
  background: linear-gradient(135deg, var(--primary-color), #867dff);
  color: var(--white);
  text-decoration: none;
  font-weight: 700;
  padding: 11px 18px;
  border-radius: 6px;
  box-shadow: 0 8px 18px rgba(108, 99, 255, 0.35);
  transition: transform 0.3s, box-shadow 0.3s;
}

.focus-produit-link:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 24px rgba(108, 99, 255, 0.45);
}

/* Actualites */
.actualites .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.actualites-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
}

.actualite-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  cursor: pointer;
}

.actualite-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
}

.actualite-image {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
}

.actualite-content {
  padding: 20px;
}

.actualite-date {
  display: inline-block;
  font-size: 12px;
  color: #777;
  margin-bottom: 10px;
}

.actualite-titre {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-color);
  margin-bottom: 10px;
  line-height: 1.35;
}

.actualite-resume {
  font-size: 14px;
  color: #666;
  margin-bottom: 14px;
  line-height: 1.5;
}

.actualite-link {
  display: inline-block;
  color: var(--primary-color);
  font-weight: 600;
  text-decoration: none;
}

.actualite-link:hover {
  color: var(--secondary-color);
  text-decoration: underline;
}

.filtres {
  display: flex;
  justify-content: center;
  gap: 15px;
  margin-bottom: 40px;
  flex-wrap: wrap;
}

.filtre-btn {
  padding: 10px 20px;
  border: 2px solid var(--primary-color);
  background: var(--white);
  color: var(--primary-color);
  border-radius: 25px;
  cursor: pointer;
  transition: all 0.3s;
  font-weight: 500;
}

.filtre-btn.active {
  background: var(--primary-color);
  color: var(--white);
}

.filtre-btn:hover {
  background: var(--primary-color);
  color: var(--white);
}

.livres-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
}

.livre-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  cursor: pointer;
}

.livre-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
}

.livre-couverture {
  width: 100%;
  height: 280px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  padding: 30px 20px;
  position: relative;
  overflow: hidden;
}

.livre-couverture::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 20% 50%, rgba(255, 255, 255, 0.1), transparent),
  radial-gradient(circle at 80% 80%, rgba(0, 0, 0, 0.1), transparent);
  pointer-events: none;
}

.livre-emoji {
  font-size: 80px;
  z-index: 1;
  animation: float 3s ease-in-out infinite;
}

@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}

.livre-couverture-content {
  text-align: center;
  z-index: 1;
  width: 100%;
}

.livre-couverture-titre {
  color: var(--white);
  font-weight: 700;
  font-size: 18px;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
  margin-bottom: 8px;
  line-height: 1.3;
  word-wrap: break-word;
}

.livre-couverture-auteur {
  color: rgba(255, 255, 255, 0.9);
  font-size: 13px;
  text-shadow: 1px 1px 3px rgba(0, 0, 0, 0.2);
  font-style: italic;
}

.livre-card:nth-child(2n) .livre-image {
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
}

.livre-card:nth-child(3n) .livre-image {
  background: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
}

.livre-card:nth-child(4n) .livre-image {
  background: linear-gradient(135deg, #43e97b 0%, #38f9d7 100%);
}

.livre-content {
  padding: 20px;
}

.livre-titre {
  font-size: 18px;
  font-weight: bold;
  margin-bottom: 10px;
  color: var(--text-color);
}

.livre-auteur {
  color: #666;
  font-size: 14px;
  margin-bottom: 10px;
}

.livre-categorie {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 12px;
  margin-bottom: 15px;
}

.livre-prix {
  font-size: 24px;
  font-weight: bold;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.livre-description {
  font-size: 13px;
  color: #666;
  margin-bottom: 15px;
  line-height: 1.5;
}

.livre-duree {
  font-size: 12px;
  color: #999;
  margin-bottom: 15px;
}

.livre-extrait {
  margin-bottom: 15px;
  padding: 12px;
  background: #f0f0f0;
  border-radius: 8px;
  border-left: 4px solid var(--primary-color);
}

.extrait-label {
  display: block;
  font-size: 12px;
  font-weight: 600;
  color: var(--primary-color);
  margin-bottom: 8px;
}

.extrait-audio {
  width: 100%;
  height: 30px;
  border-radius: 4px;
}

.extrait-audio::-webkit-media-controls-panel {
  background-color: #fff;
  border-radius: 4px;
}

.extrait-audio::-webkit-media-controls-play-button,
.extrait-audio::-webkit-media-controls-mute-button,
.extrait-audio::-webkit-media-controls-volume-slider {
  filter: invert(0.8);
}

.btn-ajouter {
  width: 100%;
  padding: 10px;
  background: var(--primary-color);
  color: var(--white);
  border: none;
  border-radius: 5px;
  cursor: pointer;
  font-weight: bold;
  transition: background 0.3s;
}

.btn-ajouter:hover {
  background: var(--secondary-color);
}

.btn-ajouter.ajoute {
  background: #28a745;
}

/* Modal Panier */
.modal {
  display: none;
  position: fixed;
  z-index: 2000;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.5);
}

.modal.active {
  display: flex;
  align-items: center;
  justify-content: center;
}

.modal-content {
  background-color: var(--white);
  padding: 30px;
  border-radius: 10px;
  max-width: 500px;
  width: 90%;
  max-height: 80vh;
  overflow-y: auto;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
}

.close {
  float: right;
  font-size: 28px;
  font-weight: bold;
  cursor: pointer;
  color: var(--text-color);
}

.close:hover {
  color: var(--secondary-color);
}

.modal-content h2,
.modal-content .titre_moyen {
  margin-bottom: 20px;
  color: var(--primary-color);
}

.panier-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 15px 0;
  border-bottom: 1px solid var(--light-bg);
}

.panier-item-info {
  flex-grow: 1;
}

.panier-item-titre {
  font-weight: bold;
  margin-bottom: 5px;
}

.panier-item-prix {
  color: var(--primary-color);
  font-weight: bold;
}

.panier-item-remove {
  background: var(--secondary-color);
  color: var(--white);
  border: none;
  padding: 5px 10px;
  border-radius: 3px;
  cursor: pointer;
  margin-left: 10px;
}

.panier-total {
  margin: 20px 0;
  font-size: 20px;
  text-align: right;
  padding: 15px;
  background: var(--light-bg);
  border-radius: 5px;
}

.panier-vide {
  text-align: center;
  padding: 30px;
  color: #666;
}

/* Contact */
.contact {
  padding: 80px 20px;
  background: var(--light-bg);
}

.contact h2,
.contact .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.contact-form {
  max-width: 600px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.contact-form input,
.contact-form textarea {
  padding: 15px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s;
}

.contact-form input:focus,
.contact-form textarea:focus {
  outline: none;
  border-color: var(--primary-color);
}

.message-success {
  background: #28a745;
  color: var(--white);
  padding: 15px;
  border-radius: 5px;
  text-align: center;
  margin-top: 20px;
}

/* Inscription */
.inscription-form {
  max-width: 500px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 15px;
}

.inscription-form input {
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s;
}

.inscription-form input:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.inscription-form button {
  margin-top: 10px;
}

.inscription-modal {
  max-width: 550px;
}

/* Page Compte */
.compte-section {
  padding: 60px 20px;
  background: linear-gradient(135deg, #f8f9ff 0%, #f3f0ff 100%);
  min-height: calc(100vh - 200px);
}

.compte-container {
  max-width: 600px;
  margin: 0 auto;
  background: var(--white);
  padding: 40px;
  border-radius: 10px;
  box-shadow: var(--shadow);
}

.compte-container h1 {
  font-size: 32px;
  color: var(--primary-color);
  margin-bottom: 10px;
  text-align: center;
}

.compte-description {
  text-align: center;
  color: #666;
  margin-bottom: 30px;
  font-size: 16px;
}

.inscription-form-page {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-group label {
  font-weight: 600;
  color: var(--text-color);
  font-size: 14px;
}

.form-group input {
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 5px;
  font-family: inherit;
  font-size: 14px;
  transition: border-color 0.3s, box-shadow 0.3s;
}

.form-group input:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.form-group small {
  font-size: 12px;
  color: #999;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.form-group.checkbox {
  flex-direction: row;
  align-items: flex-start;
  gap: 10px;
}

.form-group.checkbox input {
  width: 20px;
  height: 20px;
  cursor: pointer;
  margin-top: 2px;
}

.checkbox-label {
  font-size: 14px;
  color: #666;
  cursor: pointer;
  font-weight: 400;
  margin: 0;
}

.btn-large {
  padding: 14px 30px;
  font-size: 16px;
  margin-top: 10px;
}

.message-large {
  text-align: center;
  padding: 40px 20px;
}

.message-large p {
  margin: 8px 0;
}

.compte-lien {
  text-align: center;
  margin-top: 30px;
  padding-top: 30px;
  border-top: 1px solid #eee;
}

.compte-lien p {
  color: #666;
}

.compte-lien a {
  color: var(--primary-color);
  text-decoration: none;
  font-weight: 600;
  transition: color 0.3s;
}

.compte-lien a:hover {
  color: var(--secondary-color);
}

/* Page Abonnement */
.abonnement-section {
  padding: 60px 20px;
  background: var(--white);
}

.abonnement-header {
  text-align: center;
  margin-bottom: 50px;
}

.abonnement-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.abonnement-description {
  font-size: 18px;
  color: #666;
  max-width: 500px;
  margin: 0 auto;
}

.tableau-container {
  margin-bottom: 60px;
  overflow-x: auto;
}

.tableau-abonnements {
  width: 100%;
  border-collapse: collapse;
  background: var(--white);
  box-shadow: var(--shadow);
  border-radius: 10px;
  overflow: hidden;
}

.tableau-abonnements thead {
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
}

.tableau-abonnements th {
  padding: 20px;
  text-align: left;
  font-weight: 600;
  font-size: 14px;
}

.tableau-abonnements td {
  padding: 20px;
  border-bottom: 1px solid #f0f0f0;
  font-size: 14px;
}

.tableau-abonnements tbody tr:last-child td {
  border-bottom: none;
}

.formule-row {
  transition: background-color 0.3s;
}

.formule-row:hover {
  background-color: #f9f8ff;
}

.formule-nom {
  position: relative;
}

.nom-formule {
  font-weight: 700;
  font-size: 16px;
  color: var(--primary-color);
}

.badge-populaire {
  display: inline-block;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: var(--white);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  margin-top: 5px;
}

.badge-premium {
  display: inline-block;
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  color: var(--white);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  margin-top: 5px;
}

.promo-badge {
  display: inline-block;
  background: #ff6b6b;
  color: var(--white);
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 12px;
  font-weight: 600;
  margin-left: 10px;
}

.prix-principal {
  font-size: 18px;
  font-weight: 700;
  color: var(--primary-color);
}

.badge-oui {
  display: inline-block;
  background: #d4edda;
  color: #155724;
  padding: 4px 8px;
  border-radius: 4px;
  font-weight: 600;
  font-size: 12px;
}

.badge-non {
  display: inline-block;
  background: #f8d7da;
  color: #721c24;
  padding: 4px 8px;
  border-radius: 4px;
  font-weight: 600;
  font-size: 12px;
}

.badge {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 12px;
}

.btn-secondary {
  background: #6c757d;
  color: var(--white);
}

.btn-secondary:hover {
  background: #5a6268;
}

.btn-special {
  background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  color: var(--white);
}

.btn-special:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(245, 87, 108, 0.4);
}

.btn-small {
  padding: 8px 16px;
  font-size: 13px;
}

.tableau-note {
  text-align: right;
  font-size: 12px;
  color: #999;
  margin-top: 15px;
}

.abonnement-section-titre {
  text-align: center;
  margin: 60px 0 40px;
}

.abonnement-section-titre h2,
.abonnement-section-titre .titre_moyen {
  font-size: 32px;
  color: var(--primary-color);
}

.avantages-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-bottom: 60px;
}

.avantage-card {
  background: var(--light-bg);
  padding: 30px;
  border-radius: 10px;
  text-align: center;
  transition: transform 0.3s, box-shadow 0.3s;
}

.avantage-card:hover {
  transform: translateY(-10px);
  box-shadow: var(--shadow);
}

.avantage-icon {
  font-size: 40px;
  margin-bottom: 15px;
}

.avantage-card h3 {
  font-size: 18px;
  color: var(--primary-color);
  margin-bottom: 10px;
}

.avantage-card p {
  color: #666;
  font-size: 14px;
}

/* FAQ */
.faq-container {
  max-width: 800px;
  margin: 0 auto;
}

.faq-item {
  background: var(--light-bg);
  border-radius: 8px;
  margin-bottom: 15px;
  overflow: hidden;
}

.faq-question {
  padding: 20px;
  cursor: pointer;
  display: flex;
  justify-content: space-between;
  align-items: center;
  user-select: none;
  transition: background 0.3s;
}

.faq-question:hover {
  background: #f0ecff;
}

.faq-toggle {
  font-size: 24px;
  color: var(--primary-color);
  font-weight: 300;
}

.faq-answer {
  padding: 0 20px 20px;
  color: #666;
  line-height: 1.6;
}

.faq-answer p {
  margin: 0;
}

/* Page Nouveautés */
.nouveaute-section {
  padding: 60px 20px;
  background: var(--white);
  min-height: 100vh;
}

.nouveaute-header {
  text-align: center;
  margin-bottom: 50px;
}

.nouveaute-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.nouveaute-description {
  font-size: 18px;
  color: #666;
  max-width: 500px;
  margin: 0 auto;
}

/* Onglets */
.onglets-container {
  margin-bottom: 40px;
}

.onglets-list {
  display: flex;
  gap: 15px;
  justify-content: center;
  flex-wrap: wrap;
  border-bottom: 2px solid #f0f0f0;
  padding-bottom: 0;
}

.onglet-btn {
  padding: 15px 25px;
  border: none;
  background: transparent;
  color: #666;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s;
  position: relative;
  display: flex;
  align-items: center;
  gap: 8px;
}

.onglet-icon {
  font-size: 18px;
}

.onglet-btn:hover {
  color: var(--primary-color);
}

.onglet-btn.active {
  color: var(--primary-color);
}

.onglet-btn.active::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));
  border-radius: 2px 2px 0 0;
}

/* Grille des Nouvelles */
.nouveaute-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 25px;
  margin-bottom: 50px;
}

.nouvelle-card {
  background: var(--white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: transform 0.3s, box-shadow 0.3s;
  display: flex;
  flex-direction: column;
}

.nouvelle-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.15);
}

.nouvelle-couverture {
  width: 100%;
  height: 200px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.nouvelle-couverture::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 20% 50%, rgba(255, 255, 255, 0.1), transparent),
  radial-gradient(circle at 80% 80%, rgba(0, 0, 0, 0.1), transparent);
  pointer-events: none;
}

.nouvelle-emoji {
  font-size: 60px;
  z-index: 1;
  animation: float 3s ease-in-out infinite;
}

.nouvelle-nouveau {
  position: absolute;
  top: 10px;
  right: 10px;
  background: #ff6b6b;
  color: var(--white);
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1px;
  box-shadow: 0 4px 10px rgba(255, 107, 107, 0.3);
  z-index: 2;
}

.nouvelle-content {
  padding: 20px;
  flex-grow: 1;
  display: flex;
  flex-direction: column;
}

.nouvelle-date {
  font-size: 11px;
  color: #999;
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.nouvelle-titre {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-color);
  margin-bottom: 8px;
  line-height: 1.3;
}

.nouvelle-auteur {
  font-size: 13px;
  color: #666;
  margin-bottom: 10px;
}

.nouvelle-categorie {
  display: inline-block;
  background: var(--light-bg);
  color: var(--primary-color);
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 11px;
  margin-bottom: 10px;
  width: fit-content;
}

.nouvelle-description {
  font-size: 13px;
  color: #666;
  margin-bottom: 10px;
  line-height: 1.5;
  flex-grow: 1;
}

.nouvelle-duree {
  font-size: 12px;
  color: #999;
  margin-bottom: 10px;
}

.nouvelle-prix {
  font-size: 20px;
  font-weight: 700;
  color: var(--primary-color);
  margin-bottom: 12px;
}

/* Pagination */
.pagination-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 30px;
  padding: 40px 20px;
  background: var(--light-bg);
  border-radius: 10px;
}

.pagination-info {
  font-size: 15px;
  color: #666;
  font-weight: 500;
}

.pagination-controls {
  display: flex;
  align-items: center;
  gap: 15px;
  flex-wrap: wrap;
  justify-content: center;
}

.pagination-btn {
  padding: 10px 18px;
  border: 2px solid var(--primary-color);
  background: var(--white);
  color: var(--primary-color);
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s;
}

.pagination-btn:hover:not(:disabled) {
  background: var(--primary-color);
  color: var(--white);
}

.pagination-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pagination-numbers {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.pagination-number {
  width: 36px;
  height: 36px;
  border: 2px solid #ddd;
  background: var(--white);
  color: var(--text-color);
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pagination-number:hover:not(.active) {
  border-color: var(--primary-color);
  color: var(--primary-color);
}

.pagination-number.active {
  background: var(--primary-color);
  color: var(--white);
  border-color: var(--primary-color);
}

.pagination-ellipsis {
  padding: 0 6px;
  color: #999;
}

/* Page Sondage */
.sondage-section {
  padding: 60px 20px;
  background: var(--white);
  min-height: 100vh;
}

.sondage-header {
  text-align: center;
  margin-bottom: 60px;
}

.sondage-header h1 {
  font-size: 36px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.sondage-description {
  font-size: 18px;
  color: #666;
  max-width: 600px;
  margin: 0 auto;
}

.sondage-form-container {
  max-width: 700px;
  margin: 0 auto;
}

.sondage-form {
  background: var(--light-bg);
  padding: 40px;
  border-radius: 10px;
  box-shadow: var(--shadow);
}

.sondage-progress {
  margin-bottom: 40px;
}

.progress-bar {
  width: 100%;
  height: 8px;
  background: #e0e0e0;
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 10px;
}

.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));
  transition: width 0.3s ease;
  width: 0%;
}

.progress-text {
  font-size: 13px;
  color: #666;
  text-align: center;
}

.sondage-question {
  margin-bottom: 35px;
  padding-bottom: 35px;
  border-bottom: 1px solid #e0e0e0;
}

.sondage-question:last-of-type {
  border-bottom: none;
}

.question-label {
  display: block;
  font-size: 16px;
  color: var(--text-color);
  margin-bottom: 20px;
  line-height: 1.5;
}

.question-response {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.question-response.stars {
  flex-direction: row;
  gap: 5px;
  justify-content: center;
  flex-wrap: wrap;
}

.question-response.stars input {
  display: none;
}

.star-label {
  font-size: 24px;
  cursor: pointer;
  transition: transform 0.2s, filter 0.2s;
  user-select: none;
  filter: grayscale(100%);
}

.question-response.stars input:checked ~ .star-label,
.star-label:hover,
.question-response.stars input:checked + .star-label ~ .star-label:hover {
  filter: grayscale(0%);
}

.question-response.stars input:checked + .star-label {
  transform: scale(1.2);
}

.radio-label,
.checkbox-label {
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  padding: 12px;
  border-radius: 6px;
  transition: all 0.3s;
  user-select: none;
}

.radio-label:hover,
.checkbox-label:hover {
  background: rgba(108, 99, 255, 0.05);
}

.radio-label input[type="radio"],
.checkbox-label input[type="checkbox"] {
  cursor: pointer;
  width: 18px;
  height: 18px;
  accent-color: var(--primary-color);
}

.radio-label span,
.checkbox-label span {
  font-size: 14px;
  color: var(--text-color);
  flex: 1;
}

.question-response textarea {
  width: 100%;
  padding: 12px;
  border: 2px solid #ddd;
  border-radius: 6px;
  font-family: inherit;
  font-size: 14px;
  resize: vertical;
  transition: border-color 0.3s;
}

.question-response textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(108, 99, 255, 0.1);
}

.question-response small {
  font-size: 12px;
  color: #999;
  margin-top: 5px;
}

.sondage-actions {
  margin-top: 40px;
  text-align: center;
}

.confidentialite {
  font-size: 12px;
  color: #999;
  margin-top: 15px;
}

.sondage-confirmation {
  max-width: 600px;
  margin: 60px auto;
  background: var(--light-bg);
  padding: 60px 40px;
  border-radius: 10px;
  text-align: center;
}

.confirmation-content {
  animation: slideIn 0.5s ease;
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.confirmation-icon {
  font-size: 60px;
  margin-bottom: 20px;
}

.sondage-confirmation h2,
.sondage-confirmation .titre_moyen {
  font-size: 28px;
  color: var(--primary-color);
  margin-bottom: 15px;
}

.sondage-confirmation p {
  font-size: 15px;
  color: #666;
  margin: 10px 0;
  line-height: 1.6;
}

.confirmation-message {
  font-weight: 500;
  color: var(--primary-color);
  margin: 20px 0;
}

.sondage-confirmation .btn-primary {
  margin-top: 30px;
}

/* Responsive - Sondage */
@media (max-width: 768px) {
  .sondage-form {
    padding: 30px 20px;
  }

  .sondage-header h1 {
    font-size: 28px;
  }

  .sondage-question {
    margin-bottom: 25px;
    padding-bottom: 25px;
  }
}

@media (max-width: 480px) {
  .sondage-section {
    padding: 30px 15px;
  }

  .sondage-form {
    padding: 20px;
  }

  .sondage-header h1 {
    font-size: 24px;
  }

  .sondage-description {
    font-size: 14px;
  }

  .question-label {
    font-size: 14px;
  }

  .question-response.stars {
    gap: 2px;
  }

  .star-label {
    font-size: 20px;
  }

  .radio-label,
  .checkbox-label {
    padding: 10px;
    font-size: 13px;
  }

  .sondage-confirmation {
    padding: 40px 20px;
  }

  .confirmation-icon {
    font-size: 48px;
  }

  .sondage-confirmation h2,
  .sondage-confirmation .titre_moyen {
    font-size: 22px;
  }
}

/* Responsive - Nouvelles */
@media (max-width: 768px) {
  .onglets-list {
    gap: 10px;
  }

  .onglet-btn {
    padding: 12px 15px;
    font-size: 13px;
  }

  .onglet-icon {
    display: none;
  }

  .nouveaute-grid {
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 15px;
  }

  .pagination-controls {
    flex-direction: column;
  }

  .pagination-numbers {
    justify-content: center;
  }
}

@media (max-width: 480px) {
  .onglet-btn {
    padding: 10px 12px;
    font-size: 12px;
  }

  .onglet-btn.active::after {
    height: 2px;
  }

  .nouveaute-grid {
    grid-template-columns: 1fr;
    gap: 15px;
  }

  .pagination-number {
    width: 32px;
    height: 32px;
    font-size: 13px;
  }

  .nouvelle-couverture {
    height: 180px;
  }

  .nouvelle-emoji {
    font-size: 50px;
  }
}

/* Carousel Section */
.carousel-section {
  padding: 80px 20px;
  background: var(--white);
}

.carousel-section h2,
.carousel-section .titre_moyen {
  font-size: 36px;
  margin-bottom: 40px;
  text-align: center;
  color: var(--primary-color);
}

.carousel-container {
  display: flex;
  align-items: center;
  gap: 20px;
  position: relative;
}

.carousel-wrapper {
  flex: 1;
  overflow: hidden;
  border-radius: 10px;
  box-shadow: var(--shadow);
  background: var(--light-bg);
}

.carousel {
  display: flex;
  transition: transform 0.5s ease-in-out;
}

.carousel-slide {
  min-width: 100%;
  display: flex;
  background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
  color: var(--white);
  padding: 40px;
  align-items: center;
  gap: 40px;
  animation: slideIn 0.5s ease-in-out;
}

@keyframes slideIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.carousel-slide-image {
  flex-shrink: 0;
  font-size: 120px;
  animation: float 3s ease-in-out infinite;
}

.carousel-slide-content {
  flex: 1;
}

.carousel-slide-title {
  font-size: 32px;
  font-weight: bold;
  margin-bottom: 15px;
}

.carousel-slide-author {
  font-size: 18px;
  opacity: 0.9;
  margin-bottom: 15px;
}

.carousel-slide-description {
  font-size: 16px;
  opacity: 0.9;
  margin-bottom: 20px;
  line-height: 1.5;
}

.carousel-slide-details {
  display: flex;
  gap: 30px;
  margin-bottom: 25px;
  flex-wrap: wrap;
}

.carousel-slide-detail {
  display: flex;
  flex-direction: column;
}

.carousel-slide-detail-label {
  font-size: 12px;
  opacity: 0.8;
  text-transform: uppercase;
  margin-bottom: 5px;
  letter-spacing: 1px;
}

.carousel-slide-detail-value {
  font-size: 20px;
  font-weight: bold;
}

.carousel-slide-price {
  font-size: 36px;
  font-weight: bold;
  margin-bottom: 25px;
}

.carousel-btn-add {
  background: var(--white);
  color: var(--primary-color);
  border: none;
  padding: 12px 30px;
  border-radius: 5px;
  font-size: 16px;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.3s;
}

.carousel-btn-add:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);
}

.carousel-btn-add.ajoute {
  background: #28a745;
  color: var(--white);
}

.carousel-btn {
  background: var(--primary-color);
  color: var(--white);
  border: none;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  cursor: pointer;
  font-size: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s;
  flex-shrink: 0;
}

.carousel-btn:hover {
  background: var(--secondary-color);
  transform: scale(1.1);
}

.carousel-btn.prev {
  order: -1;
}

.carousel-dots {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin-top: 25px;
  flex-wrap: wrap;
}

.carousel-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: #ddd;
  cursor: pointer;
  transition: all 0.3s;
  border: 2px solid transparent;
}

.carousel-dot.active {
  background: var(--primary-color);
  width: 30px;
  border-radius: 6px;
}

.carousel-dot:hover {
  background: var(--secondary-color);
}

@media (max-width: 768px) {
  .carousel-slide {
    flex-direction: column;
    padding: 30px 20px;
    gap: 20px;
  }

  .carousel-slide-image {
    font-size: 80px;
  }

  .carousel-slide-title {
    font-size: 24px;
  }

  .carousel-slide-details {
    gap: 15px;
  }

  .carousel-slide-price {
    font-size: 28px;
  }

  .carousel-btn {
    width: 40px;
    height: 40px;
    font-size: 18px;
  }
}

@media (max-width: 480px) {
  .carousel-container {
    gap: 10px;
  }

  .carousel-slide {
    padding: 20px 15px;
  }

  .carousel-slide-image {
    font-size: 60px;
  }

  .carousel-slide-title {
    font-size: 20px;
  }

  .carousel-slide-author {
    font-size: 14px;
  }

  .carousel-slide-description {
    font-size: 14px;
  }

  .carousel-btn {
    width: 35px;
    height: 35px;
    font-size: 16px;
  }

  .carousel-btn-add {
    padding: 10px 20px;
    font-size: 14px;
  }
}

/* Footer */
.footer {
  background: var(--text-color);
  color: var(--white);
  padding: 40px 20px;
  text-align: center;
}

.footer p {
  margin: 10px 0;
}

.footer-extra {
  margin-top: 24px;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.2);
}

.footer-columns {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 20px;
  text-align: left;
}

.footer-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 8px 18px;
  align-items: center;
}

.footer-list li {
  margin: 0;
}

.footer-list a,
.footer-accessibility {
  color: rgba(255, 255, 255, 0.9);
  text-decoration: none;
  font-size: 14px;
}

.footer-list a:hover {
  color: #fff;
  text-decoration: underline;
}

.footer-list .footer-accessibility {
  color: rgba(255, 255, 255, 0.9);
  font-size: 14px;
}

/* Responsive */
@media (max-width: 768px) {
  .nav-links {
    gap: 15px;
  }

  .hero-content h1,
  .hero-content h2 {
    font-size: 32px;
  }

  .livres-grid {
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 20px;
  }

  .focus-produit-card {
    grid-template-columns: 1fr 1fr;
    gap: 20px;
  }

  .focus-produit-image {
    min-height: 240px;
  }

  .focus-produit-titre {
    font-size: 26px;
  }

  .actualites-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .catalogue h2,
  .contact h2,
  .catalogue .titre_moyen,
  .contact .titre_moyen {
    font-size: 28px;
  }

  .form-row {
    grid-template-columns: 1fr;
  }

  .compte-container {
    padding: 30px 20px;
  }

  .livre-couverture {
    height: 240px;
  }

  .livre-emoji {
    font-size: 60px;
  }

  .livre-couverture-titre {
    font-size: 16px;
  }

  .footer-columns {
    grid-template-columns: 1fr;
    text-align: center;
  }
}

@media (max-width: 480px) {
  .nav-links {
    gap: 10px;
    flex-wrap: wrap;
  }

  .hero-content h1,
  .hero-content h2 {
    font-size: 24px;
  }

  .livres-grid {
    grid-template-columns: 1fr;
  }

  .focus-produit-section {
    padding: 50px 15px;
  }

  .focus-produit-content {
    padding: 20px;
  }

  .focus-produit-titre {
    font-size: 22px;
  }

  .focus-produit-resume {
    font-size: 14px;
  }

  .focus-produit-link {
    width: 100%;
    text-align: center;
  }

  .actualites-grid {
    grid-template-columns: 1fr;
  }

  .modal-content {
    padding: 20px;
  }

  .compte-section {
    padding: 30px 15px;
  }

  .compte-container {
    padding: 20px;
  }

  .compte-container h1 {
    font-size: 24px;
  }

  .livre-couverture {
    height: 200px;
  }

  .livre-emoji {
    font-size: 50px;
  }

  .livre-couverture-titre {
    font-size: 14px;
  }

  .livre-couverture-auteur {
    font-size: 11px;
  }
}

.social {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  padding: 20px;
  background-color: #333;
  color: #fff;
}

.social .titre_moyen {
  font-size: 20px;
  font-weight: 700;
}

.social-links {
  display: flex;
  gap: 1.5rem;
  margin-top: 1rem;
  justify-content: center;
}

.social-links a {
  width: 2rem;
  height: 2rem;
  color: #fff;
  transition: color 0.3s ease;
}

.social-links a:hover {
  color: #667eea;
}

.social-links svg {
  width: 100%;
  height: 100%;
}
